1	/** A cell's position on an infinite grid, expressed as [x, y]. */
2	export type Cell = [number, number];
3	
4	/** A canonical string form of a cell, used as a Map/Set key. */
5	type CellKey = string;
6	
7	const toKey = ([x, y]: Cell): CellKey => `${x},${y}`;
8	
9	const fromKey = (key: CellKey): Cell => {
10	  const [x, y] = key.split(",").map(Number);
11	  return [x, y];
12	};
13	
14	/** Offsets of the eight neighbours surrounding any cell. */
15	const NEIGHBOR_OFFSETS: readonly Cell[] = [
16	  [-1, -1], [0, -1], [1, -1],
17	  [-1,  0],          [1,  0],
18	  [-1,  1], [0,  1], [1,  1],
19	];
20	
21	/** Yields the eight neighbouring cells around the given cell. */
22	function* neighborsOf([x, y]: Cell): Iterable<Cell> {
23	  for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	    yield [x + dx, y + dy];
25	  }
26	}
27	
28	/**
29	 * Computes the next generation of live cells under Conway's Game of Life rules.
30	 *
31	 * @param liveCells - The currently live cells; any coordinate not listed is dead.
32	 * @returns The live cells in the next generation.
33	 */
34	export function nextGeneration(liveCells: Cell[]): Cell[] {
35	  const liveKeys = new Set(liveCells.map(toKey));
36	  const neighborCounts = new Map<CellKey, number>();
37	
38	  for (const cell of liveCells) {
39	    for (const neighbor of neighborsOf(cell)) {
40	      const key = toKey(neighbor);
41	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
42	    }
43	  }
44	
45	  const isAliveNextGen = (key: CellKey, count: number): boolean =>
46	    count === 3 || (count === 2 && liveKeys.has(key));
47	
48	  const nextGen: Cell[] = [];
49	  for (const [key, count] of neighborCounts) {
50	    if (isAliveNextGen(key, count)) nextGen.push(fromKey(key));
51	  }
52	  return nextGen;
53	}
